const payload = $json?.data?.run;
if (!payload) {
  throw new Error('Run payload missing from API response.');
}
const normalized = {
  ...payload,
  project_id: payload.projectId ?? null,
  persona_id: payload.personaId ?? null,
  chat_id: payload.chatId ?? null,
  result: payload.result ?? null,
  started_at: payload.startedAt ?? null,
  completed_at: payload.completedAt ?? null,
  created_at: payload.createdAt ?? null,
  updated_at: payload.updatedAt ?? null,
  input: payload.input ?? {},
  metadata: payload.metadata ?? {},
};
return [{ json: normalized }];
